<?php require_once dirname(__DIR__) . '/includes/auth.php'; require_admin(); $rows=db()->query('SELECT l.*,s.email FROM email_send_log l JOIN subscribers s ON s.id=l.subscriber_id ORDER BY l.id DESC LIMIT 300')->fetchAll(); include '_header.php'; ?>
